export function getProductBySlug(slug) {
  if (!slug) return null;
  // Direct match
  let p = PRODUCTS.find(p => p.slug === slug);
  if (p) return p;
  // City suffix variants: "banquetes-en-cdmx" → "banquetes"
  const citySuffixes = ['ciudad-de-mexico','estado-de-mexico','guadalajara','monterrey','queretaro',
    'puebla','cancun','merida','aguascalientes','leon','los-cabos','morelia','oaxaca','pachuca',
    'puerto-vallarta','san-luis-potosi','san-miguel-allende','tijuana','toluca','torreon','veracruz',
    'cdmx','gdl','mty','df'];
  for (const city of citySuffixes) {
    if (slug.endsWith('-en-' + city)) {
      p = PRODUCTS.find(p => p.slug === slug.slice(0, -(city.length + 4)));
      if (p) return { ...p, slug };
    }
    if (slug.endsWith('-' + city)) {
      p = PRODUCTS.find(p => p.slug === slug.slice(0, -(city.length + 1)));
      if (p) return { ...p, slug };
    }
  }
  return null;
}

export function getRelatedProducts(slug, limit = 4) {
  const product = getProductBySlug(slug);
  if (!product) return [];
  return PRODUCTS
    .filter(p => p.slug !== slug && p.category === product.category)
    .slice(0, limit);
}

